        const dx = (circle as Record<string, ESObject>).x as number - (this.x as number);
        const dy = (circle as Record<string, ESObject>).y as number - (this.y as number);
        const radii = (this.radius as number) + ((circle as Record<string, ESObject>).radius as number);

