        else {
            console.log("x:", this.x, "y:", this.y, "raidus:", this.radius);
        }
    }

    x: ESObject;
    y: ESObject;
    radius: ESObject;
    minX: number;
    minY: number;
    maxX: ESObject;
    maxY: ESObject;
}

