        if (this.minX >= x || this.maxX <= x) { return false }
        if (this.minY >= y || this.maxY <= y) { return false }

        return true
    }

    getSqrDistance(x: ESObject, y: ESObject): number {
        let tmp: number
        let sqDist = 0

        if (x < this.minX) {
            tmp = (this.minX - x)
            sqDist += tmp * tmp
        }
        if (x > this.maxX) {
            tmp = (x - this.maxX)
            sqDist += tmp * tmp
        }

        if (y < this.minY) {
            tmp = (this.minY - y)
            sqDist += tmp * tmp
        }
        if (y > this.maxY) {
            tmp = (y - this.maxY)
            sqDist += tmp * tmp
        }

