        }
    }

    lerp(src: Vector3, alpha: number): void {
        this.x += (src.x - this.x) * alpha;
        this.y += (src.y - this.y) * alpha;
        this.z += (src.z - this.z) * alpha;
    }

    cross(src: Vector3): void {
        const x = this.x;
        const y = this.y;
        const z = this.z;

        this.x = y * src.z - z * src.y;
        this.y = z * src.x - x * src.z;
        this.z = x * src.y - y * src.x;
    }

    distanceToSquared(src: Vector3): number {
        const dx = this.x - src.x;
        const dy = this.y - src.y;
        const dz = this.z - src.z;

        return dx * dx + dy * dy + dz * dz;
    }

    distanceTo(src: Vector3): number {
        const dx = this.x - src.x;
        const dy = this.y - src.y;
        const dz = this.z - src.z;

        return Math.sqrt(dx * dx + dy * dy + dz * dz);
    }

    equals(src: Vector3): boolean {
        return ((this.x === src.x) && (this.y === src.y) && (this.z === src.z));
    }

    toFloat32Array(): Float32Array {
        if (!this.v) {
            this.v = new Float32Array([this.x, this.y, this.z]);
        } else {
            this.v[0] = this.x;
            this.v[1] = this.y;
            this.v[2] = this.z;
        }

        return this.v;
    }

    print(txt?: string): void {
        if (txt) {
            console.log(`${txt} Vector3(${this.x}, ${this.y}, ${this.z})`);
        } else {
            console.log(`Vector3(${this.x}, ${this.y}, ${this.z})`);
        }
    }
}
